import { useState } from 'react';import { useSearchParams } from 'react-router-dom';import { Alert } from '@/components/ui/alert';import { Button } from '@/components/ui/button';import { usePermissions } from '@/hooks/usePermissions';import { apiErrorMessage } from '@/lib/apiClient';import { useActivateSupplier,useArchiveSupplier,useSaveSupplier,useSuppliers,useVendorCategories } from '../api/useVendors';import { CategoryManager } from '../components/CategoryManager';import { SupplierForm } from '../components/SupplierForm';import { SupplierTable } from '../components/SupplierTable';import { VendorModal } from '../components/VendorModal';import type { Supplier,SupplierFormValues } from '../types';
export const SupplierListPage=()=>{const [sp,setSp]=useSearchParams();const [editing,setEditing]=useState<Supplier|null|undefined>();const [showCategories,setShowCategories]=useState(false);const {can}=usePermissions();const page=Number(sp.get('page')||1);const filters={search:sp.get('search')||'',status:sp.get('status')||'',category_id:sp.get('category_id')||'',country:sp.get('country')||'',include_archived:sp.get('include_archived')||'',sort:sp.get('sort')||'company_name',page,per_page:20};const list=useSuppliers(filters);const categories=useVendorCategories();const save=useSaveSupplier(editing?.id);const archive=useArchiveSupplier();const activate=useActivateSupplier();const items=list.data?.data.map(x=>x.attributes)??[];const set=(key:string,value:string)=>{const n=new URLSearchParams(sp);if(value)n.set(key,value);else n.delete(key);if(key!=='page')n.set('page','1');setSp(n);};const submit=async(v:SupplierFormValues)=>{await save.mutateAsync(v);setEditing(undefined);};return <div className="space-y-5 text-slate-800 dark:text-slate-100"><header className="flex flex-col gap-3 sm:flex-row sm:items-end sm:justify-between"><div><p className="text-xs font-bold uppercase tracking-[.18em] text-indigo-600">Vendor Management</p><h1 className="mt-2 text-2xl font-bold">Suppliers</h1><p className="mt-1 text-sm text-slate-500">Search, assess, archive, and maintain supplier relationships.</p></div><div className="flex gap-2">{can('vendors.manage')?<Button variant="secondary" onClick={()=>setShowCategories(true)}>Manage Categories</Button>:null}{can('vendors.create')?<Button onClick={()=>setEditing(null)}>Create Supplier</Button>:null}</div></header><section className="grid gap-3 rounded-xl border border-slate-200 bg-white p-4 sm:grid-cols-2 xl:grid-cols-5 dark:border-slate-700 dark:bg-slate-900"><input className="h-10 rounded-lg border px-3 text-sm dark:border-slate-600 dark:bg-slate-800" placeholder="Search suppliers…" value={filters.search} onChange={e=>set('search',e.target.value)}/><select className="h-10 rounded-lg border bg-white px-3 text-sm dark:border-slate-600 dark:bg-slate-800" value={filters.status} onChange={e=>set('status',e.target.value)}><option value="">All statuses</option>{['active','inactive','on_hold','archived'].map(x=><option key={x} value={x}>{x.replaceAll('_',' ')}</option>)}</select><select className="h-10 rounded-lg border bg-white px-3 text-sm dark:border-slate-600 dark:bg-slate-800" value={filters.category_id} onChange={e=>set('category_id',e.target.value)}><option value="">All categories</option>{categories.data?.map(x=><option key={x.id} value={x.id}>{x.name}</option>)}</select><input className="h-10 rounded-lg border px-3 text-sm dark:border-slate-600 dark:bg-slate-800" placeholder="Country" value={filters.country} onChange={e=>set('country',e.target.value)}/><label className="flex h-10 items-center gap-2 text-sm"><input type="checkbox" checked={filters.include_archived==='true'} onChange={e=>set('include_archived',String(e.target.checked))}/> Include archived</label></section>{list.error||archive.error||activate.error?<Alert variant="danger" title="Supplier operation failed">{apiErrorMessage(list.error||archive.error||activate.error)}</Alert>:null}<section className="overflow-hidden rounded-xl border border-slate-200 bg-white shadow-sm dark:border-slate-700 dark:bg-slate-900"><SupplierTable suppliers={items} isLoading={list.isLoading} onEdit={can('vendors.update')?setEditing:undefined} onArchive={can('vendors.delete')?s=>{if(confirm(`Archive ${s.company_name}? Existing purchasing history will be retained.`))archive.mutate(s.id);}:undefined} onActivate={can('vendors.manage')?s=>activate.mutate(s.id):undefined} onSort={field=>set('sort',sp.get('sort')===field?`-${field}`:field)}/></section>{list.data?<div className="flex items-center justify-between text-sm"><span className="text-slate-500">{list.data.meta.total} suppliers</span><div className="flex gap-2"><Button variant="secondary" size="sm" disabled={page<=1} onClick={()=>set('page',String(page-1))}>Previous</Button><Button variant="secondary" size="sm" disabled={page>=list.data.meta.last_page} onClick={()=>set('page',String(page+1))}>Next</Button></div></div>:null}{editing!==undefined?<VendorModal title={editing?'Edit Supplier':'Create Supplier'} onClose={()=>setEditing(undefined)} wide><SupplierForm supplier={editing} categories={categories.data??[]} onSubmit={v=>void submit(v)} onCancel={()=>setEditing(undefined)} isLoading={save.isPending} error={save.error?apiErrorMessage(save.error):null}/></VendorModal>:null}{showCategories?<VendorModal title="Supplier Categories" onClose={()=>setShowCategories(false)}><CategoryManager categories={categories.data??[]}/></VendorModal>:null}</div>;};
